// ============================================================================
// NEXOVA LICENSE ENGINE — CLIENT-SIDE ASYMMETRIC VERIFICATION
// Runs before any app logic. Blocks execution if unlicensed/expired/tampered.
// Uses Ed25519 via SubtleCrypto. No network calls — fully offline.
// ============================================================================

'use strict';

const LicenseEngine = (() => {
  // ── Embedded Ed25519 Public Key (DER-encoded, base64) ─────────────────────
  // This key was generated by: node license-keygen.js generate
  // Only the corresponding private key (stored offline by the developer) can
  // produce tokens that pass verification here.
  const PUBLIC_KEY_B64 = 'MCowBQYDK2VwAyEAAmPdCoDENbcrE6zLVqX0WUtnV9VRsL05HwFD9ypEARo=';

  const STORAGE_KEY_LICENSE    = 'nexova_license_token';
  const STORAGE_KEY_ANCHOR     = 'last_known_secure_time';
  const STORAGE_KEY_EULA       = 'eula_accepted';
  const CLOCK_SKEW_TOLERANCE_MS = 60 * 1000; // 1 minute grace

  // ── Hardware Fingerprint (browser-native, no OS calls) ────────────────────
  async function generateHWID() {
    // Combine multiple entropy sources available in the browser
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    ctx.textBaseline = 'top';
    ctx.font = '14px Arial';
    ctx.fillText('NexovaPOS-HWID-Seed', 2, 2);
    const canvasData = canvas.toDataURL();

    const components = [
      navigator.userAgent,
      navigator.language,
      String(screen.width * screen.height),
      String(screen.colorDepth),
      String(navigator.hardwareConcurrency || 0),
      String(navigator.deviceMemory || 0),
      new Intl.DateTimeFormat().resolvedOptions().timeZone,
      canvasData.slice(-128) // canvas fingerprint tail
    ].join('|');

    const encoded = new TextEncoder().encode(components);
    const hashBuf = await crypto.subtle.digest('SHA-256', encoded);
    const hashArr = Array.from(new Uint8Array(hashBuf));
    return hashArr.map(b => b.toString(16).padStart(2, '0')).join('').toUpperCase().slice(0, 32);
  }

  // ── Import public key for verification ───────────────────────────────────
  async function importPublicKey() {
    const binaryDer = Uint8Array.from(atob(PUBLIC_KEY_B64), c => c.charCodeAt(0));
    return crypto.subtle.importKey(
      'spki', binaryDer.buffer,
      { name: 'Ed25519' },
      false, ['verify']
    );
  }

  // ── Verify a license token string ─────────────────────────────────────────
  async function verifyToken(tokenB64, hwid) {
    try {
      const decoded      = atob(tokenB64);
      const pipeIndex    = decoded.lastIndexOf('|');
      if (pipeIndex === -1) return { valid: false, reason: 'Malformed token structure.' };

      const payloadStr  = decoded.substring(0, pipeIndex);
      const sigBase64   = decoded.substring(pipeIndex + 1);
      const sigBytes    = Uint8Array.from(atob(sigBase64), c => c.charCodeAt(0));
      const payloadBytes = new TextEncoder().encode(payloadStr);

      const pubKey = await importPublicKey();
      const signatureOk = await crypto.subtle.verify('Ed25519', pubKey, sigBytes, payloadBytes);
      if (!signatureOk) return { valid: false, reason: 'Cryptographic signature invalid.' };

      const payload = JSON.parse(payloadStr);
      if (payload.hwid !== hwid) return { valid: false, reason: `Hardware ID mismatch. Token HWID: ${payload.hwid.slice(0,8)}...` };
      if (payload.exp < Date.now()) return { valid: false, reason: `License expired on ${new Date(payload.exp).toLocaleDateString()}.` };

      return { valid: true, payload };
    } catch (err) {
      return { valid: false, reason: `Verification error: ${err.message}` };
    }
  }

  // ── Monotonic Time Anchor check ───────────────────────────────────────────
  async function checkTimeAnchor() {
    try {
      const db = await NexovaDB.getPreference(STORAGE_KEY_ANCHOR);
      if (!db) return { tampered: false };
      const lastKnown = parseInt(db);
      if (isNaN(lastKnown)) return { tampered: false };
      const now = Date.now();
      if (now < lastKnown - CLOCK_SKEW_TOLERANCE_MS) {
        return { tampered: true, lastKnown, osClock: now };
      }
    } catch (e) { /* DB not ready yet */ }
    return { tampered: false };
  }

  // ── Hard lockout overlay ───────────────────────────────────────────────────
  function mountLockoutOverlay(message, onSubmit) {
    document.getElementById('license-lockout-overlay')?.remove();
    const overlay = document.createElement('div');
    overlay.id = 'license-lockout-overlay';
    overlay.style.cssText = `
      position: fixed; inset: 0; z-index: 999999;
      background: #060608;
      display: flex; flex-direction: column; align-items: center; justify-content: center;
      font-family: 'Manrope', sans-serif; padding: 32px;
    `;
    overlay.innerHTML = `
      <div style="max-width: 480px; width: 100%; text-align: center;">
        <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="#ef4444" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" style="margin-bottom: 24px;">
          <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/>
          <line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/>
        </svg>
        <div style="font-size: clamp(18px,3vw,24px); font-weight: 800; color: #f8fafc; letter-spacing: -0.02em; margin-bottom: 12px;">
          NEXOVA POS — ACCESS RESTRICTED
        </div>
        <div style="font-size: 13px; color: #94a3b8; line-height: 1.6; margin-bottom: 32px; border: 1px solid rgba(239,68,68,0.2); border-radius: 8px; padding: 16px; background: rgba(239,68,68,0.05);">
          ${message}
        </div>
        <input id="license-input" type="text" placeholder="Paste license token here..."
          style="width: 100%; box-sizing: border-box; padding: 14px 16px; background: #121217; border: 1px solid #333; border-radius: 6px; color: #f8fafc; font-family: monospace; font-size: 11px; margin-bottom: 12px; outline: none;"
        />
        <button id="license-activate-btn"
          style="width: 100%; padding: 14px; background: #10b981; color: #060608; font-weight: 800; font-size: 13px; border: none; border-radius: 6px; cursor: pointer; letter-spacing: 0.05em; text-transform: uppercase; transition: opacity 0.15s;"
          onmousedown="this.style.opacity='0.7'" onmouseup="this.style.opacity='1'"
        >ACTIVATE LICENSE</button>
        <p style="font-size: 10px; color: #475569; margin-top: 20px;">Contact support to obtain your license key.</p>
      </div>
    `;
    document.body.appendChild(overlay);
    document.getElementById('license-activate-btn').addEventListener('click', async () => {
      const token = document.getElementById('license-input').value.trim();
      if (token) await onSubmit(token);
    });
  }

  function mountClockTamperOverlay(lastKnown, osClock) {
    document.getElementById('license-lockout-overlay')?.remove();
    const overlay = document.createElement('div');
    overlay.id = 'license-lockout-overlay';
    overlay.style.cssText = `
      position: fixed; inset: 0; z-index: 999999;
      background: #0a0005;
      display: flex; flex-direction: column; align-items: center; justify-content: center;
      font-family: 'Manrope', sans-serif; padding: 32px;
    `;
    overlay.innerHTML = `
      <div style="max-width: 480px; width: 100%; text-align: center;">
        <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="#f59e0b" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" style="margin-bottom: 24px;">
          <circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/>
          <line x1="12" y1="16" x2="12.01" y2="16"/>
        </svg>
        <div style="font-size: clamp(18px,3vw,22px); font-weight: 800; color: #f59e0b; letter-spacing: -0.02em; margin-bottom: 12px;">
          SYSTEM CLOCK TAMPERING DETECTED
        </div>
        <div style="font-size: 13px; color: #94a3b8; line-height: 1.6; margin-bottom: 24px; border: 1px solid rgba(245,158,11,0.2); border-radius: 8px; padding: 16px; background: rgba(245,158,11,0.05);">
          The system clock appears to have been moved backward.<br><br>
          Last verified secure time: <strong style="color:#f8fafc">${new Date(lastKnown).toLocaleString()}</strong><br>
          Current OS clock: <strong style="color:#ef4444">${new Date(osClock).toLocaleString()}</strong><br><br>
          Connect to an NTP server or correct your system clock to resume.
        </div>
        <button onclick="location.reload()"
          style="padding: 14px 32px; background: #f59e0b; color: #0a0005; font-weight: 800; font-size: 13px; border: none; border-radius: 6px; cursor: pointer; text-transform: uppercase;">
          RETRY AFTER CLOCK CORRECTION
        </button>
      </div>
    `;
    document.body.appendChild(overlay);
  }

  // ── EULA check ─────────────────────────────────────────────────────────────
  async function isEulaAccepted() {
    try {
      const val = await NexovaDB.getPreference(STORAGE_KEY_EULA);
      return val === 'true';
    } catch { return false; }
  }

  // ── Public API ─────────────────────────────────────────────────────────────
  async function init() {
    // Demo Mode, Local Filesystem, or non-secure contexts fallback bypass
    const urlParams = new URLSearchParams(window.location.search);
    const isLocalContext = window.location.protocol === 'file:' || 
                           window.location.hostname === 'localhost' || 
                           window.location.hostname === '127.0.0.1' || 
                           urlParams.get('demo') === 'true';

    if (isLocalContext || !window.crypto || !window.crypto.subtle) {
      console.log("[License] Running in local/demo context or Web Crypto unavailable. Bypassing license gate.");
      window.__nexovaTier = 'ENTERPRISE';
      window.__nexovaHWID = 'DEV_LOCAL_BYPASS';
      return true; // Auto-verify
    }

    // 1. Monotonic time anchor check — prevent clock rollback license bypass
    const { tampered, lastKnown, osClock } = await checkTimeAnchor();
    if (tampered) {
      mountClockTamperOverlay(lastKnown, osClock);
      return false; // Block app
    }

    // 2. Generate HWID
    const hwid = await generateHWID();
    console.log(`[License] Hardware fingerprint: ${hwid.slice(0,8)}...`);

    // 3. Check stored license
    const stored = localStorage.getItem(STORAGE_KEY_LICENSE);
    if (stored) {
      const result = await verifyToken(stored, hwid);
      if (result.valid) {
        console.log(`[License] Valid — Tier: ${result.payload.tier}, Expires: ${new Date(result.payload.exp).toLocaleDateString()}`);
        // Expose tier to app
        window.__nexovaTier = result.payload.tier;
        window.__nexovaHWID = hwid;
        return true;
      } else {
        console.warn('[License] Stored token invalid:', result.reason);
      }
    }

    // 4. No valid license — mount lockout overlay
    mountLockoutOverlay(
      stored
        ? `Your license is invalid or expired.<br><br><em>${document.getElementById('license-lockout-overlay') ? '' : ''}</em>Enter a new license token to continue.`
        : `No license found for this device.<br><br>Purchase a license and enter your token below to activate Nexova POS.`,
      async (token) => {
        const result = await verifyToken(token, hwid);
        if (result.valid) {
          localStorage.setItem(STORAGE_KEY_LICENSE, token);
          window.__nexovaTier = result.payload.tier;
          window.__nexovaHWID = hwid;
          document.getElementById('license-lockout-overlay')?.remove();
          window.location.reload();
        } else {
          const input = document.getElementById('license-input');
          if (input) {
            input.style.borderColor = '#ef4444';
            input.placeholder = `Invalid: ${result.reason}`;
            input.value = '';
          }
        }
      }
    );
    return false; // Block app
  }

  // Called on every successful checkout to update the time anchor
  async function updateTimeAnchor() {
    try {
      await NexovaDB.setPreference(STORAGE_KEY_ANCHOR, String(Date.now()));
    } catch (e) { /* non-fatal */ }
  }

  return { init, updateTimeAnchor, generateHWID };
})();
